import{_ as a,o as d,c as e,a3 as o}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"🔍 智能 OCR 进阶配置","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/smart-ocr/advanced.md","filePath":"user-guide/tools/smart-ocr/advanced.md","lastUpdated":1778244893000}'),r={name:"user-guide/tools/smart-ocr/advanced.md"};function l(i,t,s,n,h,c){return d(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="🔍-智能-ocr-进阶配置" tabindex="-1">🔍 智能 OCR 进阶配置 <a class="header-anchor" href="#🔍-智能-ocr-进阶配置" aria-label="Permalink to &quot;🔍 智能 OCR 进阶配置&quot;">​</a></h1><blockquote><p>深入掌握 OCR 引擎切换、语言模型选择与精度优化技巧。</p></blockquote><hr><h2 id="ocr-引擎对比" tabindex="-1">OCR 引擎对比 <a class="header-anchor" href="#ocr-引擎对比" aria-label="Permalink to &quot;OCR 引擎对比&quot;">​</a></h2><p>智能 OCR 内置 <strong>4 种引擎</strong>，各有优劣：</p><table tabindex="0"><thead><tr><th>引擎</th><th>速度</th><th>精度</th><th>离线</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Native OCR</strong>（系统原生）</td><td>⚡ 极快</td><td>⭐⭐⭐</td><td>✅ 完全离线</td><td>清晰印刷体、实时截屏识别</td></tr><tr><td><strong>Tesseract.js</strong>（本地）</td><td>🚀 快</td><td>⭐⭐⭐⭐</td><td>✅ 完全离线</td><td>多语言文档、扫描件</td></tr><tr><td><strong>云端 OCR</strong></td><td>🐢 取决于网络</td><td>⭐⭐⭐⭐</td><td>❌ 需联网</td><td>高精度需求、百度云等专业服务</td></tr><tr><td><strong>VLM</strong>（视觉语言模型）</td><td>🐌 较慢</td><td>⭐⭐⭐⭐⭐</td><td>❌ 需联网</td><td>复杂排版、手写体、模糊图片</td></tr></tbody></table><p>![引擎选择界面]（TODO: 截图 - 控制面板的引擎类型下拉框）</p><hr><h2 id="tesseract-js-引擎" tabindex="-1">Tesseract.js 引擎 <a class="header-anchor" href="#tesseract-js-引擎" aria-label="Permalink to &quot;Tesseract.js 引擎&quot;">​</a></h2><h3 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li>中英文混合文档</li><li>扫描版 PDF（图片格式）</li><li>离线工作环境</li></ul><h3 id="语言包选择" tabindex="-1">语言包选择 <a class="header-anchor" href="#语言包选择" aria-label="Permalink to &quot;语言包选择&quot;">​</a></h3><p>Tesseract 引擎支持多种语言，系统会自动扫描可用语言包：</p><table tabindex="0"><thead><tr><th>语言选项</th><th>代码</th></tr></thead><tbody><tr><td>简体中文 + 英文</td><td><code>chi_sim+eng</code>（默认）</td></tr><tr><td>繁体中文 + 英文</td><td><code>chi_tra+eng</code></td></tr><tr><td>简体中文</td><td><code>chi_sim</code></td></tr><tr><td>英文</td><td><code>eng</code></td></tr><tr><td>日文</td><td><code>jpn</code></td></tr><tr><td>韩文</td><td><code>kor</code></td></tr></tbody></table><blockquote><p><strong>提示</strong>：语言包文件位于 <code>public/tesseract-lang/</code> 目录，支持添加更多语言包文件（<code>.traineddata.gz</code>），系统会自动识别。</p></blockquote><h3 id="并发数调优" tabindex="-1">并发数调优 <a class="header-anchor" href="#并发数调优" aria-label="Permalink to &quot;并发数调优&quot;">​</a></h3><p>Tesseract 使用 Worker 池实现并发识别：</p><ul><li><strong>默认</strong>：4 个并发 Worker</li><li><strong>范围</strong>：1 ~ 24</li><li><strong>建议</strong>：CPU 核心数 × 2。例如 8 核 CPU 可设为 16</li><li><strong>效果</strong>：增加并发数可显著缩短批量处理时间，但会占用更多内存</li></ul><hr><h2 id="native-ocr-引擎" tabindex="-1">Native OCR 引擎 <a class="header-anchor" href="#native-ocr-引擎" aria-label="Permalink to &quot;Native OCR 引擎&quot;">​</a></h2><h3 id="适用场景-1" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景-1" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li>Windows 系统原生 OCR（Windows.Media.Ocr）</li><li>需要快速识别的实时场景</li><li>清晰的印刷体英文/中文</li></ul><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h3><ul><li><strong>速度最快</strong>：无需加载模型，直接调用系统 API</li><li><strong>完全离线</strong>：不依赖网络</li><li><strong>精度有限</strong>：对复杂排版和手写体支持较弱</li><li><strong>无需配置</strong>：切换即可使用，无需选择语言或模型</li></ul><hr><h2 id="云端-ocr-引擎" tabindex="-1">云端 OCR 引擎 <a class="header-anchor" href="#云端-ocr-引擎" aria-label="Permalink to &quot;云端 OCR 引擎&quot;">​</a></h2><h3 id="适用场景-2" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景-2" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li>需要专业 OCR 服务的高精度场景</li><li>有现成的百度云等 OCR 账号</li></ul><h3 id="支持的服务商" tabindex="-1">支持的服务商 <a class="header-anchor" href="#支持的服务商" aria-label="Permalink to &quot;支持的服务商&quot;">​</a></h3><table tabindex="0"><thead><tr><th>服务商</th><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><strong>百度云 OCR</strong></td><td>✅ 已实现</td><td>需要 API Key + Secret</td></tr><tr><td><strong>自定义 OCR</strong></td><td>✅ 已实现</td><td>支持任意 HTTP API，通过请求模板配置</td></tr><tr><td>腾讯云 OCR</td><td>⏳ 占位</td><td>暂未实现（被 VLM 替代）</td></tr><tr><td>阿里云 OCR</td><td>⏳ 占位</td><td>暂未实现（被 VLM 替代）</td></tr></tbody></table><h3 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h3><ol><li>在 <strong>设置 → OCR 服务</strong> 中配置云端 OCR 账号</li><li>确保配置的服务已启用</li><li>在控制面板中选择对应的云端服务</li></ol><blockquote><p><strong>注意</strong>：如果控制面板显示&quot;请先在设置中配置云端 OCR 服务&quot;的黄色提示，说明还没有配置任何云端 OCR 账号。</p></blockquote><h3 id="百度云-ocr-配置" tabindex="-1">百度云 OCR 配置 <a class="header-anchor" href="#百度云-ocr-配置" aria-label="Permalink to &quot;百度云 OCR 配置&quot;">​</a></h3><ol><li>前往 <a href="https://console.bce.baidu.com/" target="_blank" rel="noreferrer">百度云控制台</a> 创建 OCR 应用</li><li>获取 <strong>API Key</strong> 和 <strong>Secret Key</strong></li><li>在设置中填入凭证，选择识别端点（通用文字识别等）</li></ol><h3 id="自定义-ocr-配置" tabindex="-1">自定义 OCR 配置 <a class="header-anchor" href="#自定义-ocr-配置" aria-label="Permalink to &quot;自定义 OCR 配置&quot;">​</a></h3><p>适合对接自有 OCR 服务的场景：</p><div><ol><li>设置请求 URL 模板（支持变量替换，如 <code>{{imageBase64}}</code>）</li><li>配置请求头和请求体模板</li><li>指定响应中提取文字结果的 JSONPath</li></ol></div><hr><h2 id="vlm-视觉语言模型-引擎" tabindex="-1">VLM（视觉语言模型）引擎 <a class="header-anchor" href="#vlm-视觉语言模型-引擎" aria-label="Permalink to &quot;VLM（视觉语言模型）引擎&quot;">​</a></h2><h3 id="适用场景-3" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景-3" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li><strong>复杂排版</strong>：表格、多栏、图文混排</li><li><strong>手写体</strong>：笔记、信件、签名</li><li><strong>低质量图片</strong>：模糊、倾斜、光照不均</li><li><strong>非常用语言</strong>：Tesseract 不支持的小语种</li></ul><h3 id="前置条件-1" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件-1" aria-label="Permalink to &quot;前置条件&quot;">​</a></h3><ol><li>在 <strong>设置 → LLM 服务</strong> 中配置支持视觉能力的模型（如 GPT-4o、Claude、Gemini 等）</li><li>确保模型标注了 <code>vision: true</code> 的视觉能力</li><li>在控制面板中选择对应的视觉模型</li></ol><h3 id="关键参数调优" tabindex="-1">关键参数调优 <a class="header-anchor" href="#关键参数调优" aria-label="Permalink to &quot;关键参数调优&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>推荐值</th><th>说明</th></tr></thead><tbody><tr><td><strong>温度</strong></td><td><code>0</code> ~ <code>0.3</code></td><td>OCR 识别建议用较低温度，输出更确定</td></tr><tr><td><strong>最大 Token</strong></td><td>4096 ~ 8192</td><td>根据需要识别的文字量调整</td></tr><tr><td><strong>并发数</strong></td><td>1 ~ 5</td><td>提高吞吐量，注意 API 限流风险</td></tr><tr><td><strong>请求延迟</strong></td><td>0 ~ 1000ms</td><td>如果触发限流错误，适当增加延迟</td></tr></tbody></table><h3 id="识别提示词" tabindex="-1">识别提示词 <a class="header-anchor" href="#识别提示词" aria-label="Permalink to &quot;识别提示词&quot;">​</a></h3><p>默认提示词：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请识别图片中的所有文字内容，直接输出文字，不要添加任何解释。</span></span></code></pre></div><p>可根据场景自定义：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请逐行识别图片中的表格文字，保持表格结构，用 | 分隔列。</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>识别并翻译这段日文文字为中文。</span></span></code></pre></div><hr><h2 id="智能切图配置" tabindex="-1">智能切图配置 <a class="header-anchor" href="#智能切图配置" aria-label="Permalink to &quot;智能切图配置&quot;">​</a></h2><p>对于<strong>长图</strong>（如截图、聊天记录、代码片段），智能切图能将其按空白区域自动分割，逐个识别后再合并，大幅提升识别质量。</p><h3 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原图 → 计算每行颜色方差 → 寻找空白间隙 → 生成切割线 → 切分识别 → 合并结果</span></span></code></pre></div><h3 id="参数详解" tabindex="-1">参数详解 <a class="header-anchor" href="#参数详解" aria-label="Permalink to &quot;参数详解&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>默认值</th><th>范围</th><th>说明</th></tr></thead><tbody><tr><td><strong>长宽比阈值</strong></td><td><code>3</code></td><td>2~10</td><td>高宽比超过此值才触发切图。设为 10≈关闭切图，设为 2≈激进切图</td></tr><tr><td><strong>空白行阈值</strong></td><td><code>0.3</code></td><td>0.01~1.0</td><td>检测空白行的敏感度。值越高越容易识别为空白行</td></tr><tr><td><strong>最小空白高度</strong></td><td><code>20px</code></td><td>10~50</td><td>空白区域低于此高度不切割，避免切碎</td></tr><tr><td><strong>最小切割高度</strong></td><td><code>680px</code></td><td>20~1000</td><td>切出的块低于此高度会与相邻块合并</td></tr><tr><td><strong>切割线偏移</strong></td><td><code>0.2</code></td><td>-1~1</td><td>切割线位置微调。负值向上，正值向下，0 居中对齐</td></tr></tbody></table><h3 id="调优场景示例" tabindex="-1">调优场景示例 <a class="header-anchor" href="#调优场景示例" aria-label="Permalink to &quot;调优场景示例&quot;">​</a></h3><p><strong>场景一：聊天记录 / 代码截图</strong></p><ul><li>长宽比阈值：<code>3</code>（触发切图）</li><li>空白行阈值：<code>0.2</code>（聊天记录行间距大，严格检测即可）</li><li>最小空白高度：<code>15px</code>（细小的空行也能识别）</li><li>最小切割高度：<code>500px</code>（切割块不要太小）</li><li>切割线偏移：<code>0</code>（居中切割，避免吞掉文字）</li></ul><p><strong>场景二：试卷 / 文档扫描件</strong></p><ul><li>长宽比阈值：<code>2</code>（A4纸竖拍，接近 1.4 比例，适当降低触发条件）</li><li>空白行阈值：<code>0.4</code>（文档空白较多，可放宽容错）</li><li>最小空白高度：<code>30px</code>（不要被细小的段落间距干扰）</li><li>最小切割高度：<code>800px</code>（保证每个块包含完整的题目）</li><li>切割线偏移：<code>0.2</code>（稍微向下，防止切割线吃掉上一行的底部）</li></ul><blockquote><p><strong>贴士</strong>：切图配置改变后，需要<strong>重新切割</strong>图片才能生效。在预览区域点击&quot;切割当前图片&quot;或&quot;切割全部&quot;即可。</p></blockquote><hr><h2 id="精度优化-checklist" tabindex="-1">精度优化 Checklist <a class="header-anchor" href="#精度优化-checklist" aria-label="Permalink to &quot;精度优化 Checklist&quot;">​</a></h2><p>如果识别结果不理想，按以下顺序排查：</p><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th><th>预期效果</th></tr></thead><tbody><tr><td>1️⃣</td><td>切换引擎试试</td><td>不同引擎擅长不同场景</td></tr><tr><td>2️⃣</td><td>调整切图参数</td><td>减少误切割或过分割</td></tr><tr><td>3️⃣</td><td>增加 Tesseract 并发</td><td>加速但不影响精度</td></tr><tr><td>4️⃣</td><td>使用 VLM + 自定义提示词</td><td>最灵活，适配复杂场景</td></tr><tr><td>5️⃣</td><td>重新识别失败块</td><td>有时只是临时网络波动</td></tr><tr><td>6️⃣</td><td>手动编辑结果</td><td>最终手段，逐块修正</td></tr></tbody></table><hr><h2 id="历史记录管理" tabindex="-1">历史记录管理 <a class="header-anchor" href="#历史记录管理" aria-label="Permalink to &quot;历史记录管理&quot;">​</a></h2><p>OCR 历史记录采用&quot;索引 + 分离文件&quot;模式：</p><ul><li><strong>索引文件</strong>：<code>history-index.json</code> — 存储列表元数据，用于快速展示</li><li><strong>详情文件</strong>：<code>history/{recordId}.json</code> — 存储完整识别结果</li></ul><p>每条历史记录包含：</p><ul><li>原始图片（通过资产管理器存储）</li><li>使用的引擎配置</li><li>完整的识别结果</li><li>时间戳</li></ul><p>删除历史记录时，关联的图片资产也会同时清理（如果未被其他模块引用）。</p><hr><blockquote><p>💡 <strong>推荐组合</strong>：日常使用 <strong>Tesseract.js</strong> + 智能切图；遇到复杂排版切到 <strong>VLM</strong>；追求速度选 <strong>Native OCR</strong>。</p></blockquote>',78)])])}const b=a(r,[["render",l]]);export{u as __pageData,b as default};
